 1	import React from 'react';
 2	import { Toolbar, ToolbarProps } from '@patternfly/react-core';
 3	import { useDeepCompareMemo } from 'use-deep-compare';
 4	import { TableBatteries } from '../types';
 5	
 6	// Note: Toolbar probably should also be a forwardRef, but the Toolbar PF component does not pass down a ref
 7	//       even though it accepts one in its props (via extending props for HTMLDivElement).
 8	export const useToolbarWithBatteries = <
 9	  TItem,
10	  TColumnKey extends string,
11	  TSortableColumnKey extends TColumnKey,
12	  TFilterCategoryKey extends string = string,
13	  TPersistenceKeyPrefix extends string = string
14	>(
15	  batteries: Omit<
16	    TableBatteries<TItem, TColumnKey, TSortableColumnKey, TFilterCategoryKey, TPersistenceKeyPrefix>,
17	    'components'
18	  >
19	): React.FC<Omit<ToolbarProps, 'ref'>> => {
20	  const { propHelpers } = batteries;
21	  return useDeepCompareMemo(
22	    () => props => <Toolbar {...propHelpers.toolbarProps} {...props} />,
23	    [propHelpers.toolbarProps]
24	  );
25	};

